import {
  Box,
  Button,
  FormControl,
  FormLabel,
  Grid,
  Input,
  Text,
  Textarea,
} from "@chakra-ui/react";
import React, { useState } from "react";
import AdminNavTop from "../AdminNavTop";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, useParams, useLocation } from "react-router-dom";
import { addVideo } from "../../Redux/AdminReducer/action";


const AddVideo = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const { id, title } = location.state;
  let obj = {
    title: title,
    description: "",
    link: "",
    views: "",
    img: "",
    courseId: id,
  };

  

  const [detail, setDetail] = useState(obj);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setDetail((prev) => {
      return { ...prev, [name]: value };
    });
  };
  const handleSubmit = () => {
    // console.log(detail);
    dispatch(addVideo(detail, detail.courseId));
    alert("Video Added Successfully");
    navigate("/admin/videos");
  };

 return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box
      maxW="700px"
      mx="auto"
      mt="80px"
      bg="white"
      p={8}
      borderRadius="lg"
      boxShadow="lg"
    >
      {/* TITLE */}
      <Text fontSize="2xl" fontWeight="bold" mb={2}>
        Add Video
      </Text>

      <Text fontSize="sm" color="gray.500" mb={6}>
        Course: {title}
      </Text>

      {/* FORM */}
      <FormControl mb={4}>
        <FormLabel>Title</FormLabel>
        <Input
          name="title"
          value={detail.title}
          onChange={handleChange}
          placeholder="Enter video title"
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Description</FormLabel>
        <Textarea
          name="description"
          value={detail.description}
          onChange={handleChange}
          placeholder="Enter description"
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Video Link (YouTube)</FormLabel>
        <Input
          name="link"
          value={detail.link}
          onChange={handleChange}
          placeholder="Paste YouTube link"
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Views</FormLabel>
        <Input
          type="number"
          name="views"
          value={detail.views}
          onChange={handleChange}
          placeholder="Enter views"
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={6}>
        <FormLabel>Thumbnail</FormLabel>
        <Input
          name="img"
          value={detail.img}
          onChange={handleChange}
          placeholder="Paste thumbnail URL"
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      {/* VIDEO PREVIEW */}
      {detail.link && (
        <Box mb={6}>
          <Text fontSize="sm" mb={2}>Preview:</Text>
          <Box
            borderRadius="md"
            overflow="hidden"
            boxShadow="md"
          >
            <iframe
              width="100%"
              height="300"
              src={detail.link.replace("watch?v=", "embed/")}
              title="video preview"
              allowFullScreen
            />
          </Box>
        </Box>
      )}

      {/* THUMBNAIL PREVIEW */}
      {detail.img && (
        <Box mb={6}>
          <Text fontSize="sm" mb={2}>Thumbnail Preview:</Text>
          <img
            src={detail.img}
            style={{
              width: "100%",
              borderRadius: 8,
            }}
          />
        </Box>
      )}

      {/* BUTTON */}
      <Button
        bg="#A435F0"
        color="white"
        size="lg"
        w="100%"
        _hover={{ bg: "#8710d8" }}
        onClick={handleSubmit}
      >
        Add Video
      </Button>
    </Box>
  </Box>
);
};

export default AddVideo;
